function getVideoId(url) {
    if (!url) return null;

    let vidId = "";

    if (url.includes("youtu.be/")) {
        vidId = url.split("youtu.be/")[1].split(/[?&]/)[0];
    } else if (url.includes("youtube.com/watch")) {
        const params = new URLSearchParams(url.split("?")[1]);
        vidId = params.get("v");
    }

    return vidId;
}

