/* =========================================
   מערכת ניהול ומחיקת תגובות (מנהלים בלבד)
   ========================================= */
let adminCommentsUnsubscribe = null;

// 1. פונקציה לטעינת התגובות עם כפתור מחיקה לתוך דף המנהלים
function initAdminCommentsManager() {
    const adminCommentsList = document.getElementById('admin-comments-list');
    
    // אם האלמנט לא קיים (המשתמש לא בדף מנהלים), עוצרים מיד!
    if (!adminCommentsList) return;

    // ניקוי האזנות קודמות למניעת כפילויות בזיכרון
    if (adminCommentsUnsubscribe) {
        adminCommentsUnsubscribe();
    }

    const commentsQuery = query(collection(db, "comments"), orderBy("timestamp", "desc"));
    
    adminCommentsUnsubscribe = onSnapshot(commentsQuery, (snapshot) => {
        adminCommentsList.innerHTML = '';
        
        if (snapshot.empty) {
            adminCommentsList.innerHTML = '<p style="color:rgba(255, 255, 255, 0.34); text-align:center;">אין תגובות במערכת.</p>';
            return;
        }

        snapshot.forEach(docSnap => {
            const data = docSnap.data();
            const commentId = docSnap.id; // האיידי הייחודי של התגובה ב-Firebase
            
            const item = document.createElement('div');
            item.className = 'admin-comment-item';
            item.innerHTML = `
                <div class="admin-comment-info">
                    <strong>👤 ${data.authorName}:</strong>
                    <span>${data.text}</span>
                </div>
                <button class="btn-delete" onclick="deleteComment('${commentId}')">
                    <i class="fa-solid fa-trash-can"></i> מחק תגובה
                </button>
            `;
            adminCommentsList.appendChild(item);
        });
    }, (error) => {
        console.error("שגיאה בטעינת תגובות למנהל:", error);
    });
}

// 2. פונקציית המחיקה מול Firebase
async function deleteComment(commentId) {
    if (!confirm("⚠️ האם אתה בטוח שברצונך למחוק לצמיתות את התגובה הזו?")) return;

    try {
        // מחיקת המסמך הספציפי לפי ה-ID שלו
        await deleteDoc(doc(db, "comments", commentId));
        alert("התגובה נמחקה בהצלחה!");
    } catch (error) {
        console.error("שגיאה במחיקת המסמך:", error);
        alert("אירעה שגיאה במחיקת התגובה. ודא שיש לך הרשאות מתאימות ב-Firebase.");
    }
}

