// משתנה גלובלי זמני שיחזיק את השאלות שנבחרו בהגרלה
let currentActiveQuestions = [];

async function renderActiveExercise(exId) {
    let subject = '';
    let cleanSubtopicId = exId; // משתנה שישמור את השם הנקי עבור פיירבייס

    // 1. זיהוי אוטומטי של הנושא הראשי - תוך התחשבות בקידומת 'ex_'
    for (const [sub, list] of Object.entries(subTopicsMap)) {
        for (const topic of list) {
            // בודק אם ה-ID תואם בדיוק, או אם הוא תואם כשמוסיפים לו 'ex_'
            if (topic.id === exId || 'ex_' + topic.id === exId) {
                subject = sub;
                cleanSubtopicId = topic.id; // ישמור את השם הנקי, למשל "kinematics"
                break;
            }
        }
        if (subject) break; // עצירת הלולאה החיצונית ברגע שמצאנו
    }

    console.log("Subject found:", subject, "| Firebase Subtopic:", cleanSubtopicId);

    // 2. משיכת השאלות החדשות שיצרת ב-Firebase עבור הנושא הזה
    if (subject) {
        // שים לב: אנחנו שולחים את cleanSubtopicId ל-Firebase ולא את exId
        const fbQuestions = await loadQuestionsFromFirebase(subject, cleanSubtopicId);
        
        // אם המערך המקומי של הנושא הזה עדיין לא קיים, ניצור אותו
        if (!window.questionsBank[exId]) {
            window.questionsBank[exId] = [];
        }
        
        // מיזוג השאלות מ-Firebase לתוך המאגר (רק שאלות שעדיין לא קיימות שם, כדי למנוע כפילויות)
        fbQuestions.forEach(fbQ => {
            const exists = window.questionsBank[exId].some(localQ => localQ.q === fbQ.q);
            if (!exists) {
                window.questionsBank[exId].push(fbQ);
            }
        });
    }

    // 3. כעת נמשוך את המאגר המעודכן (שכולל גם את השאלות המקוריות וגם את שלך!)
    const allQuestions = window.questionsBank[exId];
    const app = document.getElementById('app-container');
    
    if (!allQuestions || allQuestions.length === 0) { 
        app.innerHTML = `<section><h2 class="section-title">אין שאלות עדיין</h2><button class="btn-back" onclick="router('home')">חזור</button></section>`; 
        return; 
    }

    // הגרלת 10 שאלות מתוך המאגר המאוחד ושמירתן במשתנה הגלובלי לתרגול
    currentActiveQuestions = [...allQuestions]
        .sort(() => 0.5 - Math.random())
        .slice(0, 10);

    let html = `
        <section style="min-height:100vh; padding-top:40px;">
            <h2 class="section-title">תרגול שאלות (10 שאלות אקראיות)</h2>
            <div class="form-container" style="text-align:right; direction:rtl; max-width:800px;">
                <div id="exercise-container">
                    ${currentActiveQuestions.map((q, i) => `
                        <div class="question-block" style="margin-bottom:30px; border: 2px solid #f1f5f9; padding:25px; border-radius:20px; background: #fff;">
                            <p style="font-size:1.3rem; font-weight:700; margin-bottom:15px; color: var(--dark);">${i+1}. ${q.q}</p>
                            <div class="options-group">
                                ${q.options.map(opt => `
                                    <label style="display:flex; align-items:center; gap:12px; margin:12px 0; cursor:pointer;">
                                        <input type="radio" name="q${i}" value="${opt}"> 
                                        <span>${opt}</span>
                                    </label>
                                `).join('')}
                            </div>
                        </div>
                     `).join('')}
                </div>
                <button id="checkBtn" class="btn-main" style="width:100%; margin-top:20px;" onclick="checkCurrentAnswers()">
                    <i class="fa-solid fa-check-double"></i> בדוק תשובות
                </button>
            </div>
            <button class="btn-back" onclick="router('exercise_list', '${subject || 'mechanics'}')">חזור לרשימה</button>
        </section>
    `;
    app.innerHTML = html;
}

