// פונקציה לחישוב הממוצע האמיתי של נושא גדול והצגתו
function calculateAndRenderSubjectAverages() {
    if (!window.physicsStructure) return;

    for (const [subjectKey] of Object.entries(window.physicsStructure)) {

        const exerciseList = window.contentData
            ? (window.contentData[`${subjectKey}_exercises`] || [])
            : [];

        let targetIds = [];

        if (exerciseList.length === 0) {
            const backupIds = {
                mechanics: ['ex_kinematics', 'ex_dynamics', 'ex_gravity', 'ex_energy', 'ex_momentum'],
                electricity: ['ex_electrostatics', 'ex_electricity', 'ex_magnetism', 'ex_induction'],
                radiation: ['ex_waves', 'ex_photons', 'ex_bohr', 'ex_nucleus']
            };
            targetIds = backupIds[subjectKey] || [];
        } else {
            targetIds = exerciseList.map(ex => ex.id);
        }

        const progress = window.playerProgress || {};

        // רק ערכים קיימים באמת
        const validValues = targetIds
            .map(id => progress[id])
            .filter(v => typeof v === 'number');

        const subjectAverage = validValues.length
            ? Math.round(validValues.reduce((a, b) => a + b, 0) / validValues.length)
            : 0;

        const progressTextElement = document.getElementById(`average-text-${subjectKey}`);
        const progressBarElement = document.getElementById(`average-bar-${subjectKey}`);

        if (progressTextElement) {
            progressTextElement.innerText = `${subjectAverage}%`;
        }

        if (progressBarElement) {
            progressBarElement.style.width = `${subjectAverage}%`;
        }
    }
}

// קריאה לפונקציה מיד עם טעינת נתוני המשתמש מ-Firebase (בתוך onAuthStateChanged או Snapshot)

window.checkCurrentAnswers = function() {
    if (!currentActiveQuestions || currentActiveQuestions.length === 0) return;
    
    let correctCount = 0;
    const questionBlocks = document.querySelectorAll('.question-block');
    const correctQuestionIds = []; // מערך שישמור את מזהי השאלות שהתלמיד צדק בהן במקץ הנוכחי

    currentActiveQuestions.forEach((q, i) => {
        const selected = document.querySelector(`input[name="q${i}"]:checked`);
        const block = questionBlocks[i];

        if (selected && selected.value === q.a) {
            correctCount++;
            block.style.border = "2px solid #22c55e";
            block.style.background = "#f0fdf4";
            addXP(100); 
            
            if (q.id) {
                correctQuestionIds.push(q.id); // שמירת מזהה השאלה הנכונה
            }
        } else {
            block.style.border = "2px solid #ef4444";
            block.style.background = "#fef2f2";
            
            const correctHint = document.createElement('p');
            correctHint.style.color = "#dc2626";
            correctHint.style.fontSize = "0.9rem";
            correctHint.style.marginTop = "10px";
            correctHint.innerHTML = `תשובה נכונה: <b>${q.a}</b>`;
            block.appendChild(correctHint);
        }
    });

    // השבתת הכפתור לאחר בדיקה
    const btn = document.getElementById('checkBtn');
    if (btn) {
        btn.disabled = true;
        btn.innerHTML = `סיימת! ${correctCount}/${currentActiveQuestions.length} תשובות נכונות`;
        btn.style.background = "#64748b";
    }

    // גלילה לתוצאה הראשונה
    if (questionBlocks[0]) {
        questionBlocks[0].scrollIntoView({ behavior: 'smooth' });
    }

    // שליחת רשימת ה-IDs שנפתרו נכון לצורך שקלול דינמי בבסיס הנתונים
    if (currentActiveQuestions[0]) {
        const exId = Object.keys(window.questionsBank).find(key => window.questionsBank[key].includes(currentActiveQuestions[0]));
        if (exId) {
            updateProgressWithCorrectIds(exId, correctQuestionIds);
        }
    }
};

async function updateProgressWithCorrectIds(exId, correctIdsInThisRun) {
    const user = auth.currentUser;
    if (!user) return;

    const allQuestionsInExercise = window.questionsBank[exId];
    if (!allQuestionsInExercise || allQuestionsInExercise.length === 0) return;

    const topic = allQuestionsInExercise[0].topic;
    const subtopic = allQuestionsInExercise[0].subtopic;

    // 1. אתחול משתני עזר במידה ואינם קיימים ב-State
    if (!window.playerStats.correctQuestionsTrack) window.playerStats.correctQuestionsTrack = [];
    if (!window.playerStats.subProgress) window.playerStats.subProgress = {};
    if (!window.playerStats.progress) window.playerStats.progress = {};

    // 2. מיזוג השאלות שנפתרו נכון כעת לתוך מאגר השאלות הכללי שהמשתמש פתר אי פעם נכון (ללא כפילויות)
    correctIdsInThisRun.forEach(id => {
        if (!window.playerStats.correctQuestionsTrack.includes(id)) {
            window.playerStats.correctQuestionsTrack.push(id);
        }
    });

    // 3. חישוב ההתקדמות לתת הנושא הנוכחי:
    // כמה מתוך *כל* השאלות הקיימות בבנק לתת-נושא זה נפתרו אי פעם נכון
    const allExpectedIdsForSubtopic = allQuestionsInExercise.map(q => q.id);
    const userCorrectIdsForSubtopic = window.playerStats.correctQuestionsTrack.filter(id => 
        allExpectedIdsForSubtopic.includes(id)
    );

    const subtopicScore = Math.round((userCorrectIdsForSubtopic.length / allExpectedIdsForSubtopic.length) * 100);
    window.playerStats.subProgress[subtopic] = subtopicScore;

    // 4. חישוב ממוצע הנושא הראשי על סמך כל תתי הנושאים שלו
    const subtopicsInTopic = physicsStructure[topic].subtopics;
    let totalTopicScore = 0;
    subtopicsInTopic.forEach(sub => {
        totalTopicScore += (window.playerStats.subProgress[sub] || 0);
    });
    const newTopicScore = Math.round(totalTopicScore / subtopicsInTopic.length);
    window.playerStats.progress[topic] = newTopicScore;

    // 5. שמירה מסודרת ל-Firestore (כולל המערך החדש שעוקב אחר ה-IDs)
    try {
        const userRef = doc(db, "users", user.uid);
        await setDoc(userRef, {
            correctQuestionsTrack: window.playerStats.correctQuestionsTrack,
            subProgress: window.playerStats.subProgress,
            progress: window.playerStats.progress
        }, { merge: true });
        console.log(`Progress updated for ${dict[subtopic].name}: ${subtopicScore}%`);
    } catch (error) {
        console.error("Error updating score to DB:", error);
    }
}

// עדכון או יצירה של אובייקט ההתקדמות הגלובלי באפליקציה
if (!window.playerProgress) {
    window.playerProgress = {};
}

// פונקציה לעדכון התקדמות הלמידה בצורה חכמה וייחודית
// פונקציה לעדכון התקדמות ב-Firestore
async function updateProgress(userId, subtopicId, newValue) {
    console.log("--- תהליך עדכון מתחיל ---");
    console.log("משתמש:", userId, "| נושא:", subtopicId, "| ערך חדש:", newValue);

    // בדיקה שה-userId קיים כדי למנוע שגיאות 404
    if (!userId) {
        console.error("שגיאה: userId ריק! לא ניתן לבצע עדכון.");
        return;
    }

    const docRef = doc(db, "users", userId);
    
    try {
        // שימוש ב-setDoc עם {merge: true} - הכי בטוח לעדכון שדות בודדים בתוך אובייקט
        await setDoc(docRef, {
            progress: {
                [subtopicId]: newValue
            }
        }, { merge: true });

        console.log("העדכון הצליח בשרת!");
        alert("ההתקדמות עודכנה בהצלחה!");

        // רענון התצוגה (UI) כדי שהשינויים יופיעו בטבלה/גרפים
        // וודא ששם הפונקציה כאן תואם לפונקציה שאחראית להצגת הנתונים שלך (למשל loadAdminPage)
        if (typeof loadAdminPage === 'function') {
            loadAdminPage();
        } else {
            console.warn("לא נמצאה פונקציה לרענון התצוגה (loadAdminPage), נא לרענן ידנית.");
        }

    } catch (error) {
        console.error("שגיאה קריטית בעדכון Firebase:", error);
        alert("שגיאה בעדכון הנתונים. בדוק ב-Console את השגיאה.");
    }
}

