function translateSubtopic(sub) {
    const dict = {
        kinematics: "קינמטיקה",
        dynamics: "דינמיקה",
        gravity: "כבידה",
        energy: "עבודה ואנרגיה",
        momentum: "תנע",
        electrostatics: "אלקטרוסטטיקה",
        circuits: "מעגלים חשמליים"
        // המשך להוסיף כאן...
    };
    return dict[sub] || sub;
}

