// משתנה גלובלי שישמור את המשתמשים לאחר הטעינה הראשונית (כדי שלא נפנה ל-Firebase בכל לחיצת כפתור)
let adminUsersCache = [];

async function loadAdminPage() {
    const app = document.getElementById('app-container');
    // מסך טעינה ראשוני
    app.innerHTML = '<div style="text-align:center; margin-top:50px; color:white; font-family: system-ui, sans-serif;">טוען נתוני מערכת... <i class="fa-solid fa-spinner fa-spin"></i></div>';

    const currentUser = auth.currentUser; 

    try {
        // 1. משיכת כל המשתמשים פעם אחת מ-Firestore ושמירתם בתוך ה-Cache
        adminUsersCache = [];
        const querySnapshot = await getDocs(collection(db, "users"));
        querySnapshot.forEach((doc) => {
            adminUsersCache.push(doc.data());
        });

        // 2. יצירת המבנה הראשי של הפאנל: כותרת, סרגל כפתורים (טאבים) וחלון תוכן משתנה
        app.innerHTML = `
            <div class="admin-container animation-fade-in" style="direction: rtl; padding: 20px; max-width: 1200px; margin: 0 auto; font-family: system-ui, sans-serif; color: white;">
                
                <div class="admin-header" style="margin-bottom: 25px; border-bottom: 2px solid rgba(255,255,255,0.1); padding-bottom: 15px;">
                    <h2><i class="fa-solid fa-shield-halved"></i> פאנל מנהלים PhysicsMaster</h2>
                    <p style="opacity: 0.7; margin-top: 5px; font-size: 0.95rem;">ניהול משתמשים, מעקב קהילה ותוכן לימודי</p>
                </div>

                <div class="admin-tabs" style="display: flex; gap: 10px; margin-bottom: 25px; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 12px; flex-wrap: wrap;">
                    <button class="admin-tab-btn active" onclick="switchAdminTab('users')">
                        <i class="fa-solid fa-users-gear"></i> הגדרות משתמשים (${adminUsersCache.length})
                    </button>
                    <button class="admin-tab-btn" onclick="switchAdminTab('comments')">
                        <i class="fa-solid fa-comments"></i> תגובות
                    </button>
                    <button class="admin-tab-btn" onclick="switchAdminTab('questions')">
                        <i class="fa-solid fa-circle-question"></i> שאלות
                    </button>
                </div>

                <div id="admin-content-window" class="admin-content-window">
                    ${getAdminUsersHtml()}
                </div>

                <button class="btn-back" onclick="router('home')" style="margin-top: 25px; padding: 10px 20px; background: rgba(255, 0, 0, 0.33); border: 1px solid rgba(255,255,255,0.2); color: white; border-radius: 10px; cursor: pointer; font-weight: bold; transition: background 0.2s;">חזרה לדף הבית</button>
            </div>
        `;

    } catch (error) {
        console.error("Error loading admin panel:", error);
        app.innerHTML = `<h3 style="text-align:center; color:red; margin-top: 50px;">שגיאה בטעינת נתונים: ${error.message}</h3><button class="btn-back" onclick="router('home')">חזור</button>`;
    }
}

// פונקציה האחראית להחליף את החלונות ואת עיצוב הכפתורים בלחיצה
function switchAdminTab(tabName) {
    // א. הסרת עיצוב "פעיל" מכל הכפתורים והוספתו רק לכפתור שנלחץ
    const buttons = document.querySelectorAll('.admin-tab-btn');
    buttons.forEach(btn => btn.classList.remove('active'));
    
    const clickedBtn = Array.from(buttons).find(btn => btn.getAttribute('onclick').includes(tabName));
    if (clickedBtn) clickedBtn.classList.add('active');

    // ב. החלפת התוכן בתוך החלון המיוחד לפי הבחירה
    const contentWindow = document.getElementById('admin-content-window');
    if (!contentWindow) return;

    if (tabName === 'users') {
        contentWindow.innerHTML = getAdminUsersHtml();
    } else if (tabName === 'comments') {
        contentWindow.innerHTML = getAdminCommentsHtml();
        // הפעלת מאזין התגובות המקורי שלך בזמן אמת ספציפית בטאב הזה
        setTimeout(initAdminCommentsManager, 0);
    } else if (tabName === 'questions') {
        contentWindow.innerHTML = getAdminQuestionsHtml();
    }
}

