window.updateSubtopicOptions = function() {

    const subjectKey =
        document.getElementById('modal-subject-select').value;

    const subtopicSelect =
        document.getElementById('modal-subtopic-select');

    if (!subtopicSelect) return;

    const subtopics =
        window.physicsStructure?.[subjectKey]?.subtopics || [];

    subtopicSelect.innerHTML = subtopics.map(sub => `
        <option value="${sub}">
            ${translateSubtopic(sub)}
        </option>
    `).join('');
};

window.processProgressAdjustment = async function(targetUid) {
    if (!targetUid) return;
    
    const subjectKey = document.getElementById('modal-subject-select').value;
    const action = document.getElementById('modal-action-select').value;
    const subtopicKey = document.getElementById('modal-subtopic-select').value;
    const userRef = doc(db, "users", targetUid);

    const rawValue = document.getElementById('modal-percentage-input').value;

    if (
        action !== 'reset' &&
        action !== 'complete' &&
        rawValue.trim() === ""
    ) {
        alert("יש להזין אחוזים");
        return;
    }

    const inputVal = parseInt(rawValue);
        
    try {
        const userDoc = await getDoc(userRef);
        let currentProgress = {};
        let questionHistory = {};
        let subProgress = {};
        let correctQuestionsTrack = [];
        
        if (userDoc.exists()) {
            currentProgress = userDoc.data().progress || {};
            questionHistory = userDoc.data().questionHistory || {};
            subProgress = userDoc.data().subProgress || {};
            correctQuestionsTrack = userDoc.data().correctQuestionsTrack || [];
        }

        // שליפת מזהי התרגולים המשויכים לנושא
        const exerciseList = window.contentData ? (window.contentData[`${subjectKey}_exercises`] || []) : [];
        let targetIds = [];

        if (exerciseList.length === 0) {
            const backupIds = {
                mechanics: ['ex_kinematics', 'ex_dynamics', 'ex_circular', 'ex_gravity', 'ex_energy', 'ex_momentum'],
                electricity: ['ex_electrostatics', 'ex_electricity', 'ex_magnetism', 'ex_induction'],
                radiation: ['ex_radiation']
            };
            targetIds = backupIds[subjectKey] || [];
        } else {
            targetIds = exerciseList
                .filter(ex => ex.id.includes(subtopicKey))
                .map(ex => ex.id);
        }

        // --- התיקון המרכזי: עדכון ההתקדמות הראשית (subProgress) ---
        let currentSubPct = subProgress[subtopicKey] || 0;
        
        if (action === 'reset') {
            subProgress[subtopicKey] = 0;
        } else if (action === 'complete') {
            subProgress[subtopicKey] = 100;
        } else if (action === 'set-custom') {
            subProgress[subtopicKey] = Math.max(0, Math.min(100, inputVal));
        } else if (action === 'add') {
            subProgress[subtopicKey] = Math.max(0, Math.min(100, currentSubPct + inputVal));
        } else if (action === 'subtract') {
            subProgress[subtopicKey] = Math.max(0, Math.min(100, currentSubPct - inputVal));
        }

        // ביצוע השינויים המתמטיים בתת-התרגולים
        targetIds.forEach(exId => {
            let currentPct = currentProgress[exId] || 0;

            if (action === 'reset') {
                delete currentProgress[exId];
                const allQuestions = window.questionsBank?.[exId] || [];

                allQuestions.forEach(q => {
                    delete questionHistory[q.id];
                });
                
                correctQuestionsTrack = correctQuestionsTrack.filter(id =>
                    !allQuestions.some(q => q.id === id)
                );
            } else if (action === 'complete') {
                currentProgress[exId] = 100;
            } else if (action === 'set-custom') {
                currentProgress[exId] = Math.max(0, Math.min(100, inputVal));
            } else if (action === 'add') {
                currentProgress[exId] = Math.max(0, Math.min(100, currentPct + inputVal));
            } else if (action === 'subtract') {
                currentProgress[exId] = Math.max(0, Math.min(100, currentPct - inputVal));
            }
        });

        // עדכון אובייקט מקומי במידה וערכת את עצמך
        if(auth.currentUser && targetUid === auth.currentUser.uid) {
            if (!window.playerStats) {
                window.playerStats = {};
            }
            window.playerStats.progress = currentProgress;
            window.playerStats.subProgress = subProgress;
            window.playerStats.correctQuestionsTrack = correctQuestionsTrack;
        }

        // כתיבה לשרת ה-Firestore
        await updateDoc(userRef, {
            progress: currentProgress,
            questionHistory: questionHistory,
            subProgress: subProgress,
            correctQuestionsTrack: correctQuestionsTrack
        });

        if (typeof renderDashboard === 'function') {
            renderDashboard();
        }
        
        if (typeof calculateAndRenderSubjectAverages === 'function') {
            calculateAndRenderSubjectAverages();
        }

        // סגירת החלון ורענון מלא
        document.getElementById('progress-settings-modal').remove();
        alert("ההתקדמות עודכנה בשרת בהצלחה! האחוזים החדשים יחושבו ויעודכנו בגרפים.");
        
        // מוודא שהמשתמש רואה את השינוי מיד בלי ללחוץ F5
        location.reload(); 

    } catch (error) {
        console.error("שגיאה בעדכון ההתקדמות במודל אדמין:", error);
        alert("אירעה שגיאה טכנית בעדכון הנתונים מול Firebase.");
    }
};

async function deleteUser(uid) {
    if(confirm('האם אתה בטוח שברצונך למחוק את המשתמש מהרשימה?')) {
        try {
            await deleteDoc(doc(db, "users", uid));
            alert('המשתמש נמחק בהצלחה');
            loadAdminPage();
        } catch (error) {
            console.error("Error deleting user:", error);
            alert("שגיאה במחיקה: " + error.message);
        }
    }
}
async function resetUserXP(uid) {
    if (!confirm("האם אתה בטוח שברצונך לאפס את ה-XP של המשתמש?")) return;

    try {
        await setDoc(doc(db, "users", uid), {
            level: 1,
            currentXP: 0,
            xpNeeded: 100,
            totalXP: 0
        }, { merge: true });

        alert("ה-XP אופס בהצלחה!");
        loadAdminPage(); // רענון הטבלה
    } catch (error) {
        console.error("Error resetting XP:", error);
        alert("שגיאה באיפוס XP");
    }
}
async function resetUserStars(uid) {
    if (!confirm("האם אתה בטוח שברצונך לאפס את הכוכבים?")) return;

    try {
        await setDoc(doc(db, "users", uid), {
            stars: 0
        }, { merge: true });

        alert("הכוכבים אופסו בהצלחה!");
        loadAdminPage();
    } catch (error) {
        console.error(error);
        alert("שגיאה באיפוס כוכבים");
    }
}

async function increaseUserStars(uid) {
    try {
        const userRef = doc(db, "users", uid);
        const snap = await getDoc(userRef);

        if (!snap.exists()) return;

        const currentStars = snap.data().stars || 0;

        await updateDoc(userRef, {
            stars: currentStars + 1
        });

        loadAdminPage();
    } catch (error) {
        console.error(error);
    }
}

async function decreaseUserStars(uid) {
    try {
        const userRef = doc(db, "users", uid);
        const snap = await getDoc(userRef);

        if (!snap.exists()) return;

        const currentStars = snap.data().stars || 0;

        await updateDoc(userRef, {
            stars: Math.max(0, currentStars - 1)
        });

        loadAdminPage();
    } catch (error) {
        console.error(error);
    }
}
window.resetUserStars = resetUserStars;
window.increaseUserStars = increaseUserStars;
window.decreaseUserStars = decreaseUserStars;
window.resetUserXP = resetUserXP;
window.deleteUser = deleteUser;
