/* =========================================
   מערכת שינוי, חיתוך וגרירת תמונת פרופיל (סטייל אינסטגרם)
   ========================================= */
let originalImageSrc = "";
let isDraggingCrop = false;
let startX = 0, startY = 0;
let currentOffsetX = 0, currentOffsetY = 0; // שומר את מרחק ההזזה של התמונה

function openProfilePicModal(event) {
    if(event) event.preventDefault();
    if (!auth.currentUser) {
        alert("עליך להיות מחובר כדי לשנות תמונת פרופיל.");
        return;
    }
    document.getElementById('profile-file-input').click();
}

function handleProfileFileSelect(event) {
    const file = event.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = function(e) {
        originalImageSrc = e.target.result;
        
        const previewImg = document.getElementById('crop-preview-img');
        previewImg.src = originalImageSrc;
        
        // איפוס מיקומים וזום מוחלט
        currentOffsetX = 0;
        currentOffsetY = 0;
        document.getElementById('profile-zoom').value = 1;
        
        previewImg.onload = function() {
            // ממקם את התמונה בדיוק באמצע כברירת מחדל
            updateCropTransform();
        };
        
        document.getElementById('profile-pic-modal').classList.add('active');
    };
    reader.readAsDataURL(file);
}

// מעדכן ויזואלית את השילוב של הזום + הגרירה
function updateCropTransform() {
    const scale = document.getElementById('profile-zoom').value;
    const previewImg = document.getElementById('crop-preview-img');
    if (previewImg) {
        previewImg.style.transform = `translate(${currentOffsetX}px, ${currentOffsetY}px) scale(${scale})`;
    }
}

// קישור פונקציית הסליידר לעדכון המשולב
function updateCropZoom() {
    updateCropTransform();
}

/* לוגיקת גרירת התמונה עם העכבר/מגע */
function startCropDrag(e) {
    isDraggingCrop = true;
    // תמיכה גם בעכבר וגם במגע סמארטפון
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    
    startX = clientX - currentOffsetX;
    startY = clientY - currentOffsetY;
}

function onCropDrag(e) {
    if (!isDraggingCrop) return;
    e.preventDefault(); // מניעת גלילה של המסך בזמן גרירה
    
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    
    currentOffsetX = clientX - startX;
    currentOffsetY = clientY - startY;
    
    updateCropTransform();
}

function endCropDrag() {
    isDraggingCrop = false;
}

function closeProfilePicModal() {
    document.getElementById('profile-pic-modal').classList.remove('active');
    document.getElementById('profile-file-input').value = '';
}

async function saveProfilePic() {
    const user = auth.currentUser;
    if (!user) return;

    const scale = parseFloat(document.getElementById('profile-zoom').value);
    
    // קנבס סופי בגודל העיגול (150x150 פיקסלים)
    const canvas = document.createElement('canvas');
    canvas.width = 150;
    canvas.height = 150;
    const ctx = canvas.getContext('2d');

    const img = new Image();
    img.src = originalImageSrc;
    
    img.onload = async function() {
        // גודל התיבה (הקונטיינר) המקורית על המסך הוא 200x200
        const containerSize = 200;

        // 1. חישוב הפרופורציה שבה התמונה מוצגת בתוך התיבה (בלי הזום)
        let renderWidth, renderHeight;
        if (img.width > img.height) {
            renderHeight = containerSize;
            renderWidth = (img.width / img.height) * containerSize;
        } else {
            renderWidth = containerSize;
            renderHeight = (img.height / img.width) * containerSize;
        }

        // היחס בין הפיקסלים האמיתיים של הקובץ לפיקסלים המוצגים על המסך
        const ratio = img.width / renderWidth;

        // 2. הכנת הציור על הקנבס - נתאים את הקנבס (150px) לקנה המידה של המסך (200px)
        // היחס בין קנבס השמירה (150) לקונטיינר התצוגה (200) הוא 0.75
        const canvasScaleModifier = 150 / containerSize; 

        // ניקוי הקנבס והעברת נקודת האמצע למרכז
        ctx.clearRect(0, 0, 150, 150);
        ctx.save();
        ctx.translate(75, 75); // זזים למרכז הקנבס

        // 3. ביצוע אותן הפעולות הוויזואליות שהמשתמש עשה: קודם הזזה (Offset) ואז הגדלה (Scale)
        // אנחנו מכפילים ב-canvasScaleModifier כדי שההזזה בפיקסלים תתאים בדיוק לגודל הקנבס הקטן יותר
        ctx.translate(currentOffsetX * canvasScaleModifier, currentOffsetY * canvasScaleModifier);
        ctx.scale(scale, scale);

        // 4. ציור התמונה בדיוק במרכז החדש שנוצר
        // רוחב וגובה הציור מותאמים ליחס הפיקסלים האמיתי של התמונה
        const finalDrawWidth = renderWidth * canvasScaleModifier;
        const finalDrawHeight = renderHeight * canvasScaleModifier;
        
        ctx.drawImage(
            img, 
            -finalDrawWidth / 2, 
            -finalDrawHeight / 2, 
            finalDrawWidth, 
            finalDrawHeight
        );
        
        ctx.restore();

        // 5. המרה ל-Base64 ושמירה בשרת
        const croppedBase64 = canvas.toDataURL('image/jpeg', 0.9);

        try {
            // שמירה ב-Firestore
            await updateDoc(doc(db, "users", user.uid), {
                photoURL: croppedBase64
            });

            // עדכון ויזואלי מיידי בפינה למעלה
            const navProfileImg = document.getElementById('user-photo');
            if (navProfileImg) {
                navProfileImg.src = croppedBase64;
            }

            alert("תמונת הפרופיל עודכנה!");
            closeProfilePicModal();
            
        } catch (error) {
            console.error("שגיאה בעדכון תמונת הפרופיל:", error);
            alert("אירעה שגיאה בעדכון התמונה.");
        }
    };
}

