// ==========================================
// שליפת שאלות מ-Firebase עבור אזור התרגול
// ==========================================
async function loadQuestionsFromFirebase(subject, subtopic) {
    try {
        const questionsRef = collection(db, "questions");
        const q = query(
            questionsRef, 
            where("subject", "==", subject), 
            where("subtopic", "==", subtopic)
        );
        
        const querySnapshot = await getDocs(q);
        const firebaseQuestions = [];
        
        querySnapshot.forEach((doc) => {
            const data = doc.data();
            
            // התאמה מושלמת למבנה של האתר שלך (q.a מכיל את טקסט התשובה)
            firebaseQuestions.push({
                q: data.text,                                // טקסט השאלה
                options: data.answers,                       // מערך 4 האופציות
                a: data.answers[data.correctIndex]           // טקסט התשובה הנכונה בפועל!
            });
        });
        
        console.log(`נמצאו ${firebaseQuestions.length} שאלות ב-Firebase עבור ${subject} -> ${subtopic}`);
        return firebaseQuestions;

    } catch (error) {
        console.error("שגיאה במשיכת שאלות מהשרת:", error);
        return [];
    }
}

